mapper.select:
SELECT model_id, manufacturer, name, transport_category, upgrade_type, upgrade_location, lap_time, top_speed, price, release_date, source, weight, drive_gears, drive_train, seats, features, performance FROM transport_model
AND ( manufacturer LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY manufacturer ASC, transport_category ASC, name ASC LIMIT #{size} OFFSET #{offset}

mapper.insert:
INSERT INTO transport_model
(
      manufacturer
    , name
    , transport_category
    , upgrade_type
    , upgrade_location
    , lap_time
    , top_speed
    , price
    , release_date
    , source
    , weight
    , drive_gears
    , drive_train
    , seats
    , performance
    , features
)
VALUES
(
      #{manufacturer}
    , #{name}
    , #{transportCategory}
    , #{upgradeType}
    , #{upgradeLocation}
    , #{lapTime}
    , #{topSpeed}
    , #{price}
    , #{releaseDate}
    , #{source}
    , #{weight}
    , #{driveGears}
    , #{driveTrain}
    , #{seats}
    , #{performance}
    , #{features}
)

mapper.update:
UPDATE transport_model
SET
      manufacturer = #{request.manufacturer}
    , name = #{request.name}
    , transport_category = #{request.transportCategory}
    , upgrade_type = #{request.upgradeType}
    , upgrade_location = #{request.upgradeLocation}
    , lap_time = #{request.lapTime}
    , top_speed = #{request.topSpeed}
    , price = #{request.price}
    , release_date = #{request.releaseDate}
    , source = #{request.source}
    , weight = #{request.weight}
    , drive_gears = #{request.driveGears}
    , drive_train = #{request.driveTrain}
    , seats = #{request.seats}
    , performance = #{request.performance}
    , features = #{request.features}
WHERE model_id = #{modelId}
